        return output;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No new input, just evaluate current state */
        break;
    }

    /* Determine control actions based on the control policy */
    bool should_open_inlet = false;
    bool should_heater_on = false;

    /* Safety: if either sensor is invalid, stay in safe idle */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        output.inlet_open = false;
        output.heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        return output;
    }

    /* Get current level and temperature */
    int current_level = controller->last_level;
    int current_temp = controller->last_temperature_c;

    /* Check low level condition: LEVEL < 55 means heater must stay off */
    bool heater_guard_low_level = (current_level < CONTROLLER_MIN_HEATING_LEVEL);

    /* Apply control policy based on level */
    if (current_level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        /* Level < 60: command INLET OPEN and HEATER OFF */
        should_open_inlet = true;
        should_heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
    } else if (current_level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        /* Level > 75: command INLET CLOSED */
        should_open_inlet = false;
        /* Heater decision based on temp */
        if (heater_guard_low_level) {
            /* Level is high but heater guard says keep off (shouldn't happen if level >= 55, but be safe) */
            should_heater_on = false;
            controller->state = CONTROLLER_STATE_SAFE_IDLE;
        } else {
            /* Check temperature for heating decision */
            if (current_temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
                /* TEMP < 45: INLET CLOSED, HEATER ON */
                should_heater_on = true;
                controller->state = CONTROLLER_STATE_HEATING;
            } else if (current_temp >= CONTROLLER_TEMP_HIGH_THRESHOLD) {
                /* TEMP > 48: INLET CLOSED, HEATER OFF */
                should_heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                /* 45 <= TEMP <= 48: check for early heater off condition */
                if (current_temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                    /* 47 <= TEMP <= 48: check if temperature is rising */
                    bool temp_rising = false;
                    if (controller->previous_temperature_c != 0 && controller->last_temperature_c > controller->previous_temperature_c) {
                        temp_rising = true;
                    }

                    if (temp_rising) {
                        /* Temperature is rising: HEATER OFF early */
                        should_heater_on = false;
                        controller->state = CONTROLLER_STATE_HOLDING;
                    } else {
                        /* Temperature not rising: hold previous safe heater state */
                        should_heater_on = true;
                        controller->state = CONTROLLER_STATE_HOLDING;
                    }
                } else {
                    /* 45 <= TEMP < 47: INLET CLOSED, hold previous safe heater state (heater ON) */
                    should_heater_on = true;
                    controller->state = CONTROLLER_STATE_HEATING;
                }
            }
        }
    } else {
        /* 60 <= LEVEL <= 75 */
        if (current_temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* TEMP < 45: INLET CLOSED, HEATER ON */
            should_open_inlet = false;
            should_heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else if (current_temp >= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* TEMP > 48: INLET CLOSED, HEATER OFF */
            should_open_inlet = false;
            should_heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        } else {
            /* 45 <= TEMP <= 48: check for early heater off condition */
            if (current_temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                /* 47 <= TEMP <= 48: check if temperature is rising */
                bool temp_rising = false;
                if (controller->previous_temperature_c != 0 && controller->last_temperature_c > controller->previous_temperature_c) {
                    temp_rising = true;
                }

                if (temp_rising) {
                    /* Temperature is rising: HEATER OFF early */
                    should_heater_on = false;
                    controller->state = CONTROLLER_STATE_HOLDING;
                } else {
                    /* Temperature not rising: hold previous safe heater state */
                    should_heater_on = true;
                    controller->state = CONTROLLER_STATE_HOLDING;
                }
            } else {
                /* 45 <= TEMP < 47: INLET CLOSED, hold previous safe heater state (heater ON) */
                should_open_inlet = false;
                should_heater_on = true;
                controller->state = CONTROLLER_STATE_HEATING;
            }
        }
    }

    /* Apply the computed actions */
    controller->inlet_open = should_open_inlet;
    controller->heater_on = should_heater_on;

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_inlet_open != controller->inlet_open) ||
                     (previous_heater_on != controller->heater_on) ||
                     (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

